/**
 * Tests unitarios: actualizarEmpresaAction
 *
 * Valida especialmente que el action usa empresa_id del formulario
 * en lugar de perfiles.empresa_id, evitando el error de constraint única
 * cuando el usuario opera en una empresa distinta a la de su perfil.
 */
import { vi, describe, test, expect, beforeEach } from 'vitest'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('next/cache', () => ({ revalidatePath: vi.fn() }))

// Supabase query builder encadenable: todos los métodos devuelven `this`,
// sólo `single()` resuelve la promesa con el valor configurado.
function makeBuilder(resolveWith: { data?: any; error?: any }) {
    const b: any = {
        select: vi.fn().mockReturnThis(),
        eq: vi.fn().mockReturnThis(),
        update: vi.fn().mockReturnThis(),
        single: vi.fn().mockResolvedValue(resolveWith),
    }
    return b
}

// Mock configurable de createServerClient
const mockGetSession = vi.fn()
const mockFrom = vi.fn()
const mockRpc = vi.fn()

vi.mock('@/lib/supabase/server', () => ({
    createServerClient: vi.fn(() =>
        Promise.resolve({
            auth: { getSession: mockGetSession },
            from: mockFrom,
            rpc: mockRpc,
        })
    ),
}))

// Admin client no se usa en actualizarEmpresaAction
vi.mock('@/lib/supabase/admin', () => ({ createAdminClient: vi.fn() }))

// ─── Helpers ──────────────────────────────────────────────────────────────────

const ID_EMPRESA_PERFIL = 'empresa-villegas-id'
const ID_EMPRESA_FORM = 'empresa-edison-id'
const CIF_NIF = '12345678A' // NIF persona → omite el SELECT previo al UPDATE

function buildSession(userId = 'user-123') {
    return { data: { session: { user: { id: userId } } } }
}

function buildPerfil(empresaId: string, rol = 'administrador') {
    return { data: { empresa_id: empresaId, rol }, error: null }
}

function makeFormData(overrides: Record<string, string> = {}) {
    const fd = new FormData()
    fd.append('razon_social', 'Edison Test S.L.')
    fd.append('cif', overrides.cif ?? CIF_NIF)
    fd.append('tipo_empresa', overrides.tipo_empresa ?? 'autonomo')
    fd.append('pais', 'España')
    fd.append('iva_predeterminado', '21')
    fd.append('retencion_predeterminada', '0')
    fd.append('regimen_iva', 'general')
    fd.append('aplica_recargo_equivalencia', 'false')
    fd.append('recargo_porcentaje', '0')
    fd.append('dias_pago_predeterminados', '30')
    if (overrides.empresa_id !== undefined) fd.append('empresa_id', overrides.empresa_id)
    if (overrides.lugar_expedicion) fd.append('lugar_expedicion', overrides.lugar_expedicion)
    if (overrides.iban) fd.append('iban', overrides.iban)
    return fd
}

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('actualizarEmpresaAction', () => {
    beforeEach(() => {
        vi.clearAllMocks()
        mockGetSession.mockResolvedValue(buildSession())
    })

    // ── Autenticación ──────────────────────────────────────────────────────

    test('devuelve error si el usuario no tiene sesión', async () => {
        mockGetSession.mockResolvedValue({ data: { session: null } })
        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData())
        expect(result.success).toBe(false)
    })

    // ── Permisos ───────────────────────────────────────────────────────────

    test('devuelve error si el rol no es admin', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL, 'usuario')))
        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/permisos/i)
    })

    // ── Empresa ID: campo oculto del formulario ────────────────────────────

    test('usa empresa_id del formulario cuando está presente', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))

        expect(result.success).toBe(true)
        // El update debe haberse ejecutado sobre la empresa del formulario, no la del perfil
        expect(updateEqArg).toBe(ID_EMPRESA_FORM)
        expect(updateEqArg).not.toBe(ID_EMPRESA_PERFIL)
    })

    test('usa empresaId del perfil como fallback cuando no hay empresa_id en el formulario', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_PERFIL }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        // Sin empresa_id en el form
        const result = await actualizarEmpresaAction(makeFormData())

        expect(result.success).toBe(true)
        expect(updateEqArg).toBe(ID_EMPRESA_PERFIL)
    })

    test('empresa_id vacío en el formulario usa el fallback del perfil', async () => {
        let updateEqArg: string | null = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockImplementation((_col: string, val: string) => {
                updateEqArg = val
                return empresaUpdateBuilder
            }),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_PERFIL }, error: null }),
        }

        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: '   ' }))

        expect(result.success).toBe(true)
        expect(updateEqArg).toBe(ID_EMPRESA_PERFIL)
    })

    // ── Validación de CIF/NIF ──────────────────────────────────────────────

    test('devuelve error si el CIF está vacío', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL)))
        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', '')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/cif.*obligatorio/i)
    })

    test('devuelve error si el CIF tiene formato inválido', async () => {
        mockFrom.mockReturnValue(makeBuilder(buildPerfil(ID_EMPRESA_PERFIL)))
        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', 'INVALIDO')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/formato/i)
    })

    test('acepta CIF empresa formato B12345678', async () => {
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        // Primera llamada a empresas: SELECT cif para comparar
        const empresaSelectBuilder = makeBuilder({ data: { cif: 'B12345678' }, error: null })
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }

        let empresasCallCount = 0
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            empresasCallCount++
            return empresasCallCount === 1 ? empresaSelectBuilder : empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const fd = makeFormData({ empresa_id: ID_EMPRESA_FORM })
        fd.set('cif', 'B12345678')
        const result = await actualizarEmpresaAction(fd)
        expect(result.success).toBe(true)
    })

    // ── Propagación de error de Supabase ───────────────────────────────────

    test('propaga error de Supabase en el update (ej. duplicate key)', async () => {
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockReturnThis(),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({
                data: null,
                error: { message: 'duplicate key value violates unique constraint "empresas_cif_key_active"' },
            }),
        }
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        const result = await actualizarEmpresaAction(makeFormData({ empresa_id: ID_EMPRESA_FORM }))
        expect(result.success).toBe(false)
        expect(result.error).toMatch(/duplicate key/i)
    })

    // ── lugar_expedicion ───────────────────────────────────────────────────

    test('guarda lugar_expedicion correctamente', async () => {
        let capturedData: any = null
        const perfilBuilder = makeBuilder(buildPerfil(ID_EMPRESA_PERFIL))
        const empresaUpdateBuilder = {
            update: vi.fn().mockImplementation((data: any) => {
                capturedData = data
                return empresaUpdateBuilder
            }),
            eq: vi.fn().mockReturnThis(),
            select: vi.fn().mockReturnThis(),
            single: vi.fn().mockResolvedValue({ data: { id: ID_EMPRESA_FORM }, error: null }),
        }
        mockFrom.mockImplementation((table: string) => {
            if (table === 'perfiles') return perfilBuilder
            return empresaUpdateBuilder
        })
        mockRpc.mockResolvedValue({ data: true, error: null })

        const { actualizarEmpresaAction } = await import('../empresa')
        await actualizarEmpresaAction(
            makeFormData({ empresa_id: ID_EMPRESA_FORM, lugar_expedicion: 'Barcelona' })
        )
        expect(capturedData?.lugar_expedicion).toBe('Barcelona')
    })
})

'use server'

import { revalidatePath } from 'next/cache'
import { createServerClient } from '@/lib/supabase/server'
import { conceptoSchema, importCSVSchema } from '@/lib/validations/concepto-schema'
import { z } from 'zod'

async function getEmpresaId() {
    const supabase = await createServerClient()
    const { data: { session } } = await supabase.auth.getSession()
    if (!session) throw new Error('No autenticado')

    const { data: perfil } = await supabase
        .from('perfiles')
        .select('empresa_id')
        .eq('user_id', session.user.id)
        .single()

    if (!perfil?.empresa_id) throw new Error('Usuario sin empresa')
    return { supabase, empresaId: perfil.empresa_id }
}

export async function crearConceptoAction(formData: FormData) {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        // Convert FormData to object with correct types
        const rawData = Object.fromEntries(formData.entries())
        const dataToValidate = {
            ...rawData,
            precio_base: Number(rawData.precio_base) || 0,
            iva_porcentaje: Number(rawData.iva_porcentaje) || 21,
            coste_interno: rawData.coste_interno ? Number(rawData.coste_interno) : undefined,
            activo: rawData.activo === 'true' || rawData.activo === 'on',
            destacado: rawData.destacado === 'true' || rawData.destacado === 'on',
            // Ensure empty string for code is treated as undefined for auto-generation
            codigo: rawData.codigo === '' ? undefined : rawData.codigo,
        }

        // If validation fails, this will throw
        const validated = conceptoSchema.parse(dataToValidate)

        // Generar código automático si no se proporcionó
        let codigo = validated.codigo
        if (!codigo) {
            const { data: codigoGenerado, error: genError } = await (supabase as any).rpc('generar_codigo_concepto', {
                p_empresa_id: empresaId,
                p_categoria: validated.categoria
            })
            if (genError) throw genError
            codigo = codigoGenerado
        }

        const { data, error } = await supabase
            .from('conceptos_catalogo')
            .insert({
                ...validated,
                codigo: codigo!,
                empresa_id: empresaId,
            })
            .select()
            .single()

        if (error) throw error

        revalidatePath('/ventas/configuracion/conceptos')
        return { success: true, data }
    } catch (error: unknown) {
        console.error('[crearConceptoAction]', error)
        if (error instanceof z.ZodError) {
            return { success: false, error: error.issues[0]?.message }
        }
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

export async function actualizarConceptoAction(conceptoId: string, formData: FormData) {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        const rawData = Object.fromEntries(formData.entries())
        const dataToValidate = {
            ...rawData,
            precio_base: Number(rawData.precio_base) || 0,
            iva_porcentaje: Number(rawData.iva_porcentaje) || 21,
            coste_interno: rawData.coste_interno ? Number(rawData.coste_interno) : undefined,
            activo: rawData.activo === 'true' || rawData.activo === 'on',
            destacado: rawData.destacado === 'true' || rawData.destacado === 'on',
            // Ensure empty string for code is treated as undefined
            codigo: rawData.codigo === '' ? undefined : rawData.codigo,
        }

        const validated = conceptoSchema.parse(dataToValidate)

        const { data, error } = await supabase
            .from('conceptos_catalogo')
            .update(validated)
            .eq('id', conceptoId)
            .eq('empresa_id', empresaId)
            .select()
            .single()

        if (error) throw error

        revalidatePath('/ventas/configuracion/conceptos')
        return { success: true, data }
    } catch (error: unknown) {
        console.error('[actualizarConceptoAction]', error)
        if (error instanceof z.ZodError) {
            return { success: false, error: error.issues[0]?.message }
        }
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

export async function eliminarConceptoAction(conceptoId: string) {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        // Verificar que no se haya usado en facturas (lineas_factura)
        const { count, error: countError } = await supabase
            .from('lineas_factura') // Using correct table name
            .select('id', { count: 'exact', head: true })
            .eq('concepto_id', conceptoId)

        if (countError) throw countError

        if (count && count > 0) {
            return {
                success: false,
                error: `No se puede eliminar. El concepto se ha usado en ${count} línea(s) de factura`
            }
        }

        const { error } = await supabase
            .from('conceptos_catalogo')
            .delete()
            .eq('id', conceptoId)
            .eq('empresa_id', empresaId)

        if (error) throw error

        revalidatePath('/ventas/configuracion/conceptos')
        return { success: true }
    } catch (error: unknown) {
        console.error('[eliminarConceptoAction]', error)
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

export async function duplicarConceptoAction(conceptoId: string) {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        // Obtener concepto original
        const { data: original, error: fetchError } = await supabase
            .from('conceptos_catalogo')
            .select('*')
            .eq('id', conceptoId)
            .eq('empresa_id', empresaId)
            .single()

        if (fetchError || !original) throw new Error('Concepto no encontrado')

        // Generar nuevo código
        const { data: nuevoCodigo, error: genError } = await (supabase as any).rpc('generar_codigo_concepto', {
            p_empresa_id: empresaId,
            p_categoria: original.categoria
        })

        if (genError) throw genError

        // Crear duplicado
        const { data, error } = await supabase
            .from('conceptos_catalogo')
            .insert({
                ...original,
                id: undefined, // Let DB generate new ID
                codigo: nuevoCodigo,
                nombre: `${original.nombre} (Copia)`,
                veces_usado: 0,
                ultima_vez_usado: null,
                created_at: undefined, // Let DB handle defaults
                updated_at: undefined,
            })
            .select()
            .single()

        if (error) throw error

        revalidatePath('/ventas/configuracion/conceptos')
        return { success: true, data }
    } catch (error: unknown) {
        console.error('[duplicarConceptoAction]', error)
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

export async function importarCSVAction(csvData: string) {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        // Parsear CSV (simplificado, usar librería como papaparse en producción)
        const lines = csvData.trim().split('\n')
        if (lines.length < 2) throw new Error('CSV vacío o sin cabecera')

        const headers = lines[0].split(',').map(h => h.trim())
        const conceptos = []

        // Limit to 100 max for safety
        const maxRows = Math.min(lines.length, 101)

        for (let i = 1; i < maxRows; i++) {
            if (!lines[i].trim()) continue;

            const values = lines[i].split(',').map(v => v.trim())
            const obj: Record<string, string> = {}
            headers.forEach((header, index) => {
                // Map header to schema keys if needed, assuming direct mapping for now
                if (values[index] !== undefined) {
                    obj[header] = values[index]
                }
            })

            // Validar con zod
            const validated = importCSVSchema.parse({
                ...obj,
                precio_base: parseFloat(obj.precio_base || '0'),
                iva_porcentaje: parseFloat(obj.iva_porcentaje || '21'),
            })

            conceptos.push({
                ...validated,
                empresa_id: empresaId,
            })
        }

        // Insertar en bulk
        const { data, error } = await supabase
            .from('conceptos_catalogo')
            .insert(conceptos)
            .select()

        if (error) throw error

        revalidatePath('/ventas/configuracion/conceptos')
        return { success: true, data, count: conceptos.length }
    } catch (error: unknown) {
        console.error('[importarCSVAction]', error)
        if (error instanceof z.ZodError) {
            return { success: false, error: 'Error de validación en el CSV' }
        }
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

export async function getEstadisticasConceptosAction() {
    try {
        const { supabase, empresaId } = await getEmpresaId()

        const { data: conceptos, error } = await supabase
            .from('conceptos_catalogo')
            .select('precio_base, veces_usado, nombre') // Added nombre for naming the most used
            .eq('empresa_id', empresaId)

        if (error) throw error
        if (!conceptos) return { success: false, error: 'No se encontraron conceptos' }

        const totalConceptos = conceptos.length
        const precioPromedio = totalConceptos > 0
            ? conceptos.reduce((sum: number, c) => sum + (c.precio_base || 0), 0) / totalConceptos
            : 0

        // Encontrar más usado
        const masUsado = totalConceptos > 0
            ? conceptos.reduce((max, c) => (c.veces_usado || 0) > (max.veces_usado || 0) ? c : max, conceptos[0])
            : null

        return {
            success: true,
            data: {
                totalConceptos,
                precioPromedio,
                masUsado,
            }
        }
    } catch (error: unknown) {
        console.error('[getEstadisticasConceptosAction]', error)
        const message = error instanceof Error ? error.message : 'Error desconocido'
        return { success: false, error: message }
    }
}

'use server'

import { createServerClient } from '@/lib/supabase/server'
import { resend } from '@/lib/email/resend'
import { renderToStream } from '@react-pdf/renderer'
import { FacturaPdfDocument } from '@/components/ventas/pdf/pdf-document'
import type { Empresa, PdfOptions } from '@/components/ventas/pdf/pdf-document'
import React from 'react'
import path from 'path'
import fs from 'fs'
import { getUserContext } from '@/app/actions/usuarios-empresas'
import { clientConfig } from '@/config/clients'

// Convert stream to buffer manually since react-pdf stream lacks standard toBuffer
async function streamToBuffer(stream: NodeJS.ReadableStream): Promise<Buffer> {
    const chunks: Uint8Array[] = []
    return new Promise((resolve, reject) => {
        stream.on('data', (chunk) => chunks.push(chunk))
        stream.on('error', (err) => reject(err))
        stream.on('end', () => resolve(Buffer.concat(chunks)))
    })
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/

function parseAndValidateEmails(str: string): { emails: string[]; error?: string } {
    const emails = str.split(',').map(e => e.trim()).filter(Boolean)
    for (const e of emails) {
        if (!EMAIL_REGEX.test(e)) return { emails: [], error: `Email no válido: ${e}` }
    }
    return { emails }
}

export async function sendFacturaEmailAction(formData: FormData) {
    const supabase = await createServerClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        return { success: false, error: 'User not authenticated' }
    }

    const facturaId = (formData.get('facturaId') as string) || ''
    const toRaw = formData.get('to')?.toString() || ''
    const ccRaw = formData.get('cc')?.toString() || ''
    const subject = (formData.get('subject') as string) || ''
    const message = (formData.get('message') as string) || ''
    const sendCopy = formData.get('sendCopy') === 'on'
    const incluirLogo = formData.get('incluirLogo') === '1'
    const plantillaMsg = (formData.get('plantilla') as string) || 'estandar'

    const { emails: to, error: toErr } = parseAndValidateEmails(toRaw)
    const { emails: cc, error: ccErr } = parseAndValidateEmails(ccRaw)

    if (toErr || ccErr) {
        return { success: false, error: toErr || ccErr }
    }
    if (!facturaId || to.length === 0) {
        return { success: false, error: 'Introduce al menos un destinatario' }
    }

    try {
        const { empresaId, rol } = await getUserContext()
        const isGlobal = !empresaId && rol === 'admin'

        const { data: perfil } = await supabase.from('perfiles').select('empresa_id, user_id').eq('user_id', user.id).single()
        const empresaFiltro = isGlobal ? undefined : (empresaId || perfil?.empresa_id)
        if (!empresaFiltro && !isGlobal) throw new Error('Usuario sin empresa asignada')

        let query = supabase
            .from('facturas')
            .select('*, cliente:clientes(*), lineas:lineas_factura(*)')
            .eq('id', facturaId)
        if (empresaFiltro) query = query.eq('empresa_id', empresaFiltro)
        const { data: factura } = await query.single()

        if (!factura) throw new Error('Factura no encontrada')

        const fullFactura = factura as any
        fullFactura.descuento_tipo = factura.descuento_tipo as 'porcentaje' | 'fijo' | null

        // Load empresa (emisor)
        const { data: empresaRow } = await supabase
            .from('empresas')
